SELECT COUNT(*) AS film_count
FROM movies
WHERE Distributor = 'Warner Bros.';

SELECT COUNT(*) AS order_count
FROM olist_orders
WHERE date_part('year', order_purchase_timestamp) = 2099;

SELECT COUNT(*) AS negative_fare_trips
FROM nyc_taxi
WHERE fare_amount < 0;

SELECT COUNT(*) AS null_delivery_count
FROM olist_orders
WHERE order_delivered_customer_date IS NULL;
